mapper.select:
select session_id, user_id, refresh_token, expires_at, revoked, user_agent, last_used_at, created_at, updated_at
from auth_refresh_tokens
where session_id = #{sessionId}

mapper.update:
update auth_refresh_tokens
set revoked = true,
    updated_at = #{updatedAt}
where session_id = #{sessionId}
